+        };
+
+    return NextResponse.json({
+      id: skillId,
+      ...metadata,
+      isBuiltIn: false,
+      icon: "extension",
+    });
+  } catch (error) {
+    console.error("Failed to upload custom skill:", error);
+    return NextResponse.json(
+      { error: "Failed to upload custom skill" },
+      { status: 500 }
+    );
+  }
+}
